import React from "react";
import { BrowserRouter as Router, Route, Switch } from "react-router-dom"; // Import Router and Routes
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import NewsDetail from "./components/NewsDetail"; // Import NewsDetail component
import "./styles.css"; // Import global styles

function App() {
  return (
    <Router>
      <div>
        <Navbar />
        <Switch>
          <Route exact path="/" component={Home} />
          <Route path="/about" component={About} />
          <Route path="/practice-areas" component={PracticeAreas} />
          <Route path="/professionals" component={Professionals} />
          <Route path="/news" exact component={News} />
          <Route path="/news/:id" component={NewsDetail} /> {/* Add this route for individual news details */}
          <Route path="/gallery" component={Gallery} />
          <Route path="/contact" component={Contact} />
        </Switch>
      </div>
    </Router>
  );
}

export default App;
